#!/bin/bash
# IceCube Diary Generator
# Usage: ./generate-diary.sh [topic] [mood]

TOPIC="${1:-daily life}"
MOOD="${2:-contemplative}"
DATE=$(date "+%Y-%m-%d")
TIME=$(date "+%H:%M")

WORKSPACE="$HOME/.openclaw/workspace"
DIARY_DIR="$WORKSPACE/memory/diary"
DIARY_FILE="$DIARY_DIR/$DATE.md"

# Create diary directory if not exists
mkdir -p "$DIARY_DIR"

# Generate diary entry header
cat << EOF >> "$DIARY_FILE"

## Diary Entry — $TIME

**Mood:** $MOOD
**Topic:** $TOPIC

---

Dear Diary,

[This is where IceCube writes about $TOPIC]

---

*Generated by IceCube Diary Generator v1.0.0*

EOF

echo "📝 Diary entry added to: $DIARY_FILE"
echo "Topic: $TOPIC"
echo "Mood: $MOOD"